mapper.select:
SELECT c.id, c.rule_name, c.rule_code, u.unit_name, sp.specialty_name, sy.system_name, mp.point_name AS measure_point_name, c.alarm_type, c.alarm_level, c.enabled, c.description, c.created_at FROM t_alarm_config c LEFT JOIN dim_unit u ON c.unit_id = u.id AND u.deleted = 0 LEFT JOIN dim_specialty sp ON c.specialty_id = sp.id AND sp.deleted = 0 LEFT JOIN dim_system sy ON c.system_id = sy.id AND sy.deleted = 0 LEFT JOIN dim_measure_point mp ON c.measure_point_id = mp.id AND mp.deleted = 0 WHERE c.deleted = 0
AND c.unit_id = #{query.unitId}
AND c.specialty_id = #{query.specialtyId}
AND c.system_id = #{query.systemId}
AND c.alarm_type = #{query.alarmType}
AND (c.rule_name LIKE CONCAT('%', #{query.keyword}, '%') OR c.rule_code LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY c.sort_order ASC, c.id DESC
